import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Installer des mods","description":"Un guide pour installer des mods pour Fabric pas à pas.","frontmatter":{"title":"Installer des mods","description":"Un guide pour installer des mods pour Fabric pas à pas.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"fr_fr/1.21.10/players/installing-mods.md","filePath":"versions/1.21.10/translated/fr_fr/players/installing-mods.md","lastUpdated":1766682904000}`);var s={name:`fr_fr/1.21.10/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installer des mods <a class="header-anchor" href="#h1" aria-label="Permalink to “Installer des mods”">​</a></h1><p>Ce guide explique en détail le processus d&#39;installation de mods pour Fabric avec le launcher Minecraft officiel.</p><p>Pour les lanceurs tiers, vous devriez consulter leur documentation.</p><h2 id="_1-telecharger-le-mod" tabindex="-1">1. Télécharger le mod <a class="header-anchor" href="#_1-telecharger-le-mod" aria-label="Permalink to “1. Télécharger le mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Ne téléchargez que des mods provenant de sources dignes de confiance. Pour plus d&#39;informations sur comment trouver des mods, voir le guide <a href="./finding-mods">Trouver des mods fiables</a>.</p></div><p>La majorité des mods requiert également Fabric API, qui peut être téléchargée depuis <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> ou <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Lorsque vous téléchargez des mods, assurez-vous :</p><ul><li>Qu&#39;ils fonctionnent sur la version de Minecraft à laquelle vous souhaitez jouer. Par exemple, un mod qui fonctionne sur la version 1.20 peut ne pas fonctionner sur la version 1.20.2.</li><li>Qu&#39;ils sont pour Fabric et pas un autre mod loader.</li><li>Et qu&#39;ils sont pour la bonne version de Minecraft (Java Edition).</li></ul><h2 id="_2-deplacer-le-mod-dans-le-dossier-mods" tabindex="-1">2. Déplacer le mod dans le dossier <code>mods</code> <a class="header-anchor" href="#_2-deplacer-le-mod-dans-le-dossier-mods" aria-label="Permalink to “2. Déplacer le mod dans le dossier mods”">​</a></h2><p>Le dossier mods peut être trouvé aux emplacements suivants pour chaque système d&#39;exploitation.</p><p>Vous pouvez généralement coller ces chemins dans la barre d&#39;adresse de votre explorateur de fichiers pour naviguer rapidement jusqu&#39;au dossier.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Une fois le dossier <code>mods</code> trouvé, vous pouvez y déplacer les fichiers <code>.jar</code> du mod.</p><p><img src="/assets/players/installing-mods.png" alt="Mods installés dans le dossier mods" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. Et voilà ! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Et voilà !”">​</a></h2><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Le lanceur Minecraft avec le profil Fabric sélectionné" loading="lazy"></p><p>Après avoir déplacé les mods dans le dossier <code>mods</code>, vous pouvez ouvrir le launcher Minecraft et sélectionner le profil Fabric depuis le menu déroulant en bas à gauche, puis appuyer sur Jouer.</p><h2 id="resolution-de-problemes" tabindex="-1">Résolution de problèmes <a class="header-anchor" href="#resolution-de-problemes" aria-label="Permalink to “Résolution de problèmes”">​</a></h2><p>Si vous rencontrez des problèmes en suivant ce guide, vous pouvez demander de l&#39;aide dans le <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord Fabric</a> dans le salon <code>#player-support</code>.</p><p>Vous pouvez également essayer de dépanner le problème vous-même en utilisant les guides de dépannage :</p><ul><li><a href="./troubleshooting/crash-reports">Rapports de plantage</a></li><li><a href="./troubleshooting/uploading-logs">Mettre en ligne des logs</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};